import React from 'react'

function PageNotFound() {
    return (
        <div className='bg-light'>
            <div className='d-flex'>
                <h1>404</h1>
                <h3>Oops! You're lost</h3>
                <p>The page you are looking for was not found.</p>
            </div>
        </div>
    )
}

export default PageNotFound
